CREATE SCHEMA sigoclinicas;

USE sigoclinicas;

/**
 * Application
 */
CREATE TABLE role (id BIGINT AUTO_INCREMENT NOT NULL, parent_id BIGINT DEFAULT NULL, name VARCHAR(255) NOT NULL, INDEX IDX_57698A6A727ACA70 (parent_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE user (id BIGINT AUTO_INCREMENT NOT NULL, username VARCHAR(255) NOT NULL, password VARCHAR(255) NOT NULL, token_valido VARCHAR(255) NOT NULL, UNIQUE INDEX UNIQ_8D93D649F85E0677 (username), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE user_has_role (user_id BIGINT NOT NULL, role_id BIGINT NOT NULL, INDEX IDX_EAB8B535A76ED395 (user_id), INDEX IDX_EAB8B535D60322AC (role_id), PRIMARY KEY(user_id, role_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE oauth2_accesstoken (id BIGINT AUTO_INCREMENT NOT NULL, client_id BIGINT NOT NULL, user_id BIGINT DEFAULT NULL, accessToken LONGTEXT DEFAULT NULL, expires DATETIME DEFAULT NULL, INDEX IDX_A2F1E43419EB6921 (client_id), INDEX IDX_A2F1E434A76ED395 (user_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE oauth2_authorizationcode (id BIGINT AUTO_INCREMENT NOT NULL, client_id BIGINT NOT NULL, user_id BIGINT DEFAULT NULL, authorizationCode VARCHAR(255) DEFAULT NULL, redirectUri LONGTEXT DEFAULT NULL, expires DATETIME DEFAULT NULL, idToken LONGTEXT DEFAULT NULL, INDEX IDX_B2E0441319EB6921 (client_id), INDEX IDX_B2E04413A76ED395 (user_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE oauth2_client (id BIGINT AUTO_INCREMENT NOT NULL, user_id BIGINT DEFAULT NULL, clientId VARCHAR(191) DEFAULT NULL, secret VARCHAR(255) DEFAULT NULL, redirectUri LONGTEXT DEFAULT NULL, grantType LONGTEXT DEFAULT NULL COMMENT '(DC2Type:array)', INDEX IDX_669FF9C9A76ED395 (user_id), UNIQUE INDEX UNIQ_A66D48A8EA1CE9BE (clientId), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE oauth2_jti (id BIGINT AUTO_INCREMENT NOT NULL, client_id BIGINT NOT NULL, subject VARCHAR(255) DEFAULT NULL, audience VARCHAR(255) DEFAULT NULL, expires DATETIME DEFAULT NULL, jti LONGTEXT DEFAULT NULL, INDEX IDX_E2BC9B7D19EB6921 (client_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE oauth2_jwt (id BIGINT AUTO_INCREMENT NOT NULL, client_id BIGINT NOT NULL, subject VARCHAR(255) DEFAULT NULL, publicKey LONGTEXT DEFAULT NULL, INDEX IDX_AA97A46719EB6921 (client_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE oauth2_publickey (id BIGINT AUTO_INCREMENT NOT NULL, client_id BIGINT NOT NULL, publicKey LONGTEXT DEFAULT NULL, privateKey LONGTEXT DEFAULT NULL, encryptionAlgorithm VARCHAR(255) DEFAULT NULL, UNIQUE INDEX UNIQ_1D7F309119EB6921 (client_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE oauth2_refreshtoken (id BIGINT AUTO_INCREMENT NOT NULL, client_id BIGINT NOT NULL, user_id BIGINT DEFAULT NULL, refreshToken VARCHAR(255) DEFAULT NULL, expires DATETIME DEFAULT NULL, INDEX IDX_5B5D887919EB6921 (client_id), INDEX IDX_5B5D8879A76ED395 (user_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE oauth2_scope (id BIGINT NOT NULL, scope VARCHAR(191) NOT NULL, isDefault TINYINT(1) DEFAULT NULL, UNIQUE INDEX UNIQ_95A8FC4EAF55D3 (scope), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE oauth2_client_to_scope (scope_id BIGINT NOT NULL, client_id BIGINT NOT NULL, INDEX IDX_163E7163682B5931 (scope_id), INDEX IDX_163E716319EB6921 (client_id), PRIMARY KEY(scope_id, client_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE oauth2_authorizationcode_to_scope (scope_id BIGINT NOT NULL, authorizationcode_id BIGINT NOT NULL, INDEX IDX_496B8749682B5931 (scope_id), INDEX IDX_496B8749C3653FF6 (authorizationcode_id), PRIMARY KEY(scope_id, authorizationcode_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE oauth2_refreshtoken_to_scope (scope_id BIGINT NOT NULL, refreshtoken_id BIGINT NOT NULL, INDEX IDX_DDC6BA21682B5931 (scope_id), INDEX IDX_DDC6BA21E8AA8CFB (refreshtoken_id), PRIMARY KEY(scope_id, refreshtoken_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE oauth2_accesstoken_to_scope (scope_id BIGINT NOT NULL, accesstoken_id BIGINT NOT NULL, INDEX IDX_C7C91A4E682B5931 (scope_id), INDEX IDX_C7C91A4EFDB3DCD1 (accesstoken_id), PRIMARY KEY(scope_id, accesstoken_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
ALTER TABLE role ADD CONSTRAINT FK_57698A6A727ACA70 FOREIGN KEY (parent_id) REFERENCES role (id);
ALTER TABLE user_has_role ADD CONSTRAINT FK_EAB8B535A76ED395 FOREIGN KEY (user_id) REFERENCES user (id);
ALTER TABLE user_has_role ADD CONSTRAINT FK_EAB8B535D60322AC FOREIGN KEY (role_id) REFERENCES role (id);
ALTER TABLE oauth2_accesstoken ADD CONSTRAINT FK_A2F1E43419EB6921 FOREIGN KEY (client_id) REFERENCES oauth2_client (id) ON DELETE CASCADE;
ALTER TABLE oauth2_accesstoken ADD CONSTRAINT FK_A2F1E434A76ED395 FOREIGN KEY (user_id) REFERENCES user (id) ON DELETE CASCADE;
ALTER TABLE oauth2_authorizationcode ADD CONSTRAINT FK_B2E0441319EB6921 FOREIGN KEY (client_id) REFERENCES oauth2_client (id) ON DELETE CASCADE;
ALTER TABLE oauth2_authorizationcode ADD CONSTRAINT FK_B2E04413A76ED395 FOREIGN KEY (user_id) REFERENCES user (id) ON DELETE CASCADE;
ALTER TABLE oauth2_client ADD CONSTRAINT FK_669FF9C9A76ED395 FOREIGN KEY (user_id) REFERENCES user (id) ON DELETE CASCADE;
ALTER TABLE oauth2_jti ADD CONSTRAINT FK_E2BC9B7D19EB6921 FOREIGN KEY (client_id) REFERENCES oauth2_client (id) ON DELETE CASCADE;
ALTER TABLE oauth2_jwt ADD CONSTRAINT FK_AA97A46719EB6921 FOREIGN KEY (client_id) REFERENCES oauth2_client (id) ON DELETE CASCADE;
ALTER TABLE oauth2_publickey ADD CONSTRAINT FK_1D7F309119EB6921 FOREIGN KEY (client_id) REFERENCES oauth2_client (id) ON DELETE CASCADE;
ALTER TABLE oauth2_refreshtoken ADD CONSTRAINT FK_5B5D887919EB6921 FOREIGN KEY (client_id) REFERENCES oauth2_client (id) ON DELETE CASCADE;
ALTER TABLE oauth2_refreshtoken ADD CONSTRAINT FK_5B5D8879A76ED395 FOREIGN KEY (user_id) REFERENCES user (id) ON DELETE CASCADE;
ALTER TABLE oauth2_client_to_scope ADD CONSTRAINT FK_163E7163682B5931 FOREIGN KEY (scope_id) REFERENCES oauth2_scope (id) ON DELETE CASCADE;
ALTER TABLE oauth2_client_to_scope ADD CONSTRAINT FK_163E716319EB6921 FOREIGN KEY (client_id) REFERENCES oauth2_client (id) ON DELETE CASCADE;
ALTER TABLE oauth2_authorizationcode_to_scope ADD CONSTRAINT FK_496B8749682B5931 FOREIGN KEY (scope_id) REFERENCES oauth2_scope (id) ON DELETE CASCADE;
ALTER TABLE oauth2_authorizationcode_to_scope ADD CONSTRAINT FK_496B8749C3653FF6 FOREIGN KEY (authorizationcode_id) REFERENCES oauth2_authorizationcode (id) ON DELETE CASCADE;
ALTER TABLE oauth2_refreshtoken_to_scope ADD CONSTRAINT FK_DDC6BA21682B5931 FOREIGN KEY (scope_id) REFERENCES oauth2_scope (id) ON DELETE CASCADE;
ALTER TABLE oauth2_refreshtoken_to_scope ADD CONSTRAINT FK_DDC6BA21E8AA8CFB FOREIGN KEY (refreshtoken_id) REFERENCES oauth2_refreshtoken (id) ON DELETE CASCADE;
ALTER TABLE oauth2_accesstoken_to_scope ADD CONSTRAINT FK_C7C91A4E682B5931 FOREIGN KEY (scope_id) REFERENCES oauth2_scope (id) ON DELETE CASCADE;
ALTER TABLE oauth2_accesstoken_to_scope ADD CONSTRAINT FK_C7C91A4EFDB3DCD1 FOREIGN KEY (accesstoken_id) REFERENCES oauth2_accesstoken (id) ON DELETE CASCADE;

/**
 * Roles padrões
 */
INSERT INTO role VALUES
  (1, null, 'guest'),
  (2,    1, 'admin'),
  (3,    1, 'proprietario'),
  (4,    1, 'gerente'),
  (5,    1, 'recepcionista'),
  (6,    1, 'assistente'),
  (7,    1, 'profissional'),
  (8,    1, 'cliente');

/**
 * Usuário padrão Addpix
 *
 * Usuário: addpix
 * Senha: addpix
 */
INSERT INTO user VALUES (
  1, -- id
  'addpix', -- username
  '[REDACTED_SECRET]', -- password
  '' -- token_valido
);
INSERT INTO user_has_role VALUES (1, 2);
INSERT INTO oauth2_client VALUES (
  1, -- id
  1, -- user_id
  'addpix', -- clientId
  NULL, -- secret
  NULL, -- redirectUri
  NULL -- grantType
);

/**
 * Cliente reconhecido pelo sistema
 *
 * Client: addpix_mobile
 * Client secret: addpix
 */
INSERT INTO oauth2_client VALUES (
  2, -- id
  NULL, -- user_id
  'addpix_mobile', -- clientId
  '[REDACTED_SECRET]', -- secret
  NULL, -- redirectUri
  NULL -- grantType
);

/**
 * Endereco
 */
CREATE TABLE endereco (id INT AUTO_INCREMENT NOT NULL, cep VARCHAR(8) DEFAULT NULL, uf VARCHAR(2) DEFAULT NULL, cidade VARCHAR(72) DEFAULT NULL, bairro VARCHAR(72) DEFAULT NULL, logradouro VARCHAR(255) DEFAULT NULL, numero VARCHAR(36) DEFAULT NULL, complemento VARCHAR(255) DEFAULT NULL, PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;

/**
 * Telefone
 */
CREATE TABLE telefone (id INT AUTO_INCREMENT NOT NULL, numero VARCHAR(20) NOT NULL, preferencial TINYINT(1) NOT NULL, PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;

/**
 * Agenda
 */
CREATE TABLE agenda (id INT AUTO_INCREMENT NOT NULL, clinica_id INT NOT NULL, profissional_id INT NOT NULL, cliente_id INT NOT NULL, data_hora DATETIME NOT NULL, status VARCHAR(255) DEFAULT 'Aguardando confirmação' NOT NULL, motivo_cancelamento VARCHAR(255) DEFAULT NULL, INDEX IDX_2CEDC8779CD3F6D6 (clinica_id), INDEX IDX_2CEDC8777ADE2C4 (profissional_id), INDEX IDX_2CEDC877DE734E51 (cliente_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE agenda_has_servico (agenda_id INT NOT NULL, servico_id INT NOT NULL, INDEX IDX_D565FBD1EA67784A (agenda_id), INDEX IDX_D565FBD182E14982 (servico_id), PRIMARY KEY(agenda_id, servico_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;

/**
 * Clinica
 */
CREATE TABLE clinica (id INT AUTO_INCREMENT NOT NULL, endereco_id INT NOT NULL, razao_social VARCHAR(255) NOT NULL, nome_fantasia VARCHAR(255) NOT NULL, email VARCHAR(255) NOT NULL, logotipo LONGTEXT NOT NULL COMMENT '(DC2Type:json)', responsavel_nome VARCHAR(255) NOT NULL, responsavel_email VARCHAR(255) NOT NULL, responsavel_telefone VARCHAR(255) NOT NULL, responsavel_genero VARCHAR(255) NOT NULL, responsavel_data_nascimento DATE DEFAULT NULL, responsavel_cpf VARCHAR(14) NOT NULL, validade_orcamento INT DEFAULT 30 NOT NULL, validade_ficha_anamnese INT DEFAULT 30 NOT NULL, sobre LONGTEXT DEFAULT NULL, fotos LONGTEXT DEFAULT NULL COMMENT '(DC2Type:json)', horarios LONGTEXT NOT NULL COMMENT '(DC2Type:json)', formasPagamento LONGTEXT NOT NULL COMMENT '(DC2Type:json)', funcionalidades LONGTEXT DEFAULT NULL COMMENT '(DC2Type:json)', ativo TINYINT(1) DEFAULT '1' NOT NULL, cnpj VARCHAR(14) DEFAULT NULL, UNIQUE INDEX UNIQ_24BC4A2E1BB76823 (endereco_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE clinica_has_telefone (clinica_id INT NOT NULL, telefone_id INT NOT NULL, INDEX IDX_EAE42CC69CD3F6D6 (clinica_id), INDEX IDX_EAE42CC692D095A9 (telefone_id), PRIMARY KEY(clinica_id, telefone_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE clinica_has_usuario (clinica_id INT NOT NULL, usuario_id INT NOT NULL, INDEX IDX_95199BED9CD3F6D6 (clinica_id), INDEX IDX_95199BEDDB38439E (usuario_id), PRIMARY KEY(clinica_id, usuario_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE clinica_has_profissional (clinica_id INT NOT NULL, profissional_id INT NOT NULL, INDEX IDX_7581EF859CD3F6D6 (clinica_id), INDEX IDX_7581EF857ADE2C4 (profissional_id), PRIMARY KEY(clinica_id, profissional_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE clinica_has_cliente (clinica_id INT NOT NULL, cliente_id INT NOT NULL, INDEX IDX_4360B0959CD3F6D6 (clinica_id), INDEX IDX_4360B095DE734E51 (cliente_id), PRIMARY KEY(clinica_id, cliente_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE clinica_has_especialidade (clinica_id INT NOT NULL, especialidade_id INT NOT NULL, INDEX IDX_66347A579CD3F6D6 (clinica_id), INDEX IDX_66347A573BA9BFA5 (especialidade_id), PRIMARY KEY(clinica_id, especialidade_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE clinica_has_servico (id INT AUTO_INCREMENT NOT NULL, clinica_id INT DEFAULT NULL, servico_id INT DEFAULT NULL, descricao VARCHAR(255) DEFAULT NULL, tempo_medio_duracao INT DEFAULT NULL, agendamento_externo TINYINT(1) DEFAULT NULL, INDEX IDX_B634587C9CD3F6D6 (clinica_id), INDEX IDX_B634587C82E14982 (servico_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;

/**
 * Profissional
 */
CREATE TABLE profissional (id INT AUTO_INCREMENT NOT NULL, user_id BIGINT NOT NULL, nome VARCHAR(255) NOT NULL, email VARCHAR(255) NOT NULL, data_nascimento DATE DEFAULT NULL, cpf VARCHAR(14) DEFAULT NULL, genero VARCHAR(255) DEFAULT 'Masculino' NOT NULL, tipo_vinculo VARCHAR(255) DEFAULT 'CLT' NOT NULL, ativo TINYINT(1) DEFAULT '1' NOT NULL, nome_conselho VARCHAR(255) DEFAULT NULL, numero_registro VARCHAR(255) NOT NULL, horarios LONGTEXT NOT NULL COMMENT '(DC2Type:json)', UNIQUE INDEX UNIQ_E41A66E5A76ED395 (user_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE profissional_has_telefone (profissional_id INT NOT NULL, telefone_id INT NOT NULL, INDEX IDX_6C86CF0A7ADE2C4 (profissional_id), INDEX IDX_6C86CF0A92D095A9 (telefone_id), PRIMARY KEY(profissional_id, telefone_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE profissional_has_intervalo (id INT AUTO_INCREMENT NOT NULL, profissional_id INT DEFAULT NULL, clinica_id INT DEFAULT NULL, tipo VARCHAR(255) DEFAULT 'Fixo' NOT NULL, motivo VARCHAR(255) DEFAULT 'Almoço' NOT NULL, dia_semana_tipo_fixo VARCHAR(255) DEFAULT NULL, data_hora_inicio DATETIME NOT NULL, data_hora_fim DATETIME NOT NULL, INDEX IDX_D98D426F7ADE2C4 (profissional_id), INDEX IDX_D98D426F9CD3F6D6 (clinica_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE profissional_has_servico (id INT AUTO_INCREMENT NOT NULL, profissional_id INT DEFAULT NULL, servico_id INT DEFAULT NULL, clinica_id INT DEFAULT NULL, tipo_comissao VARCHAR(255) DEFAULT 'Percentual' NOT NULL, valor_comissao NUMERIC(10, 2) NOT NULL, INDEX IDX_70540AC7ADE2C4 (profissional_id), INDEX IDX_70540AC82E14982 (servico_id), INDEX IDX_70540AC9CD3F6D6 (clinica_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;

/**
 * Usuário
 */
CREATE TABLE usuario (id INT AUTO_INCREMENT NOT NULL, user_id BIGINT NOT NULL, nome VARCHAR(255) NOT NULL, email VARCHAR(255) NOT NULL, data_nascimento DATE DEFAULT NULL, cpf VARCHAR(14) DEFAULT NULL, genero VARCHAR(255) DEFAULT 'Masculino' NOT NULL, tipo_vinculo VARCHAR(255) DEFAULT 'CLT' NOT NULL, ativo TINYINT(1) DEFAULT '1' NOT NULL, UNIQUE INDEX UNIQ_2265B05DA76ED395 (user_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE usuario_has_telefone (usuario_id INT NOT NULL, telefone_id INT NOT NULL, INDEX IDX_3A6C9C80DB38439E (usuario_id), INDEX IDX_3A6C9C8092D095A9 (telefone_id), PRIMARY KEY(usuario_id, telefone_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;

/**
 * Cliente
 */
CREATE TABLE cliente (id INT AUTO_INCREMENT NOT NULL, endereco_id INT NOT NULL, user_id BIGINT NOT NULL, nome VARCHAR(255) NOT NULL, email VARCHAR(255) NOT NULL, data_nascimento DATE DEFAULT NULL, genero VARCHAR(255) DEFAULT NULL, cpf VARCHAR(14) DEFAULT NULL, convenios VARCHAR(255) DEFAULT NULL, nome_dependentes LONGTEXT DEFAULT NULL, origem VARCHAR(255) NOT NULL, UNIQUE INDEX UNIQ_F41C9B25E7927C74 (email), UNIQUE INDEX UNIQ_F41C9B253E3E11F0 (cpf), UNIQUE INDEX UNIQ_F41C9B251BB76823 (endereco_id), UNIQUE INDEX UNIQ_F41C9B25A76ED395 (user_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE cliente_has_telefone (cliente_id INT NOT NULL, telefone_id INT NOT NULL, INDEX IDX_6458DFE7DE734E51 (cliente_id), INDEX IDX_6458DFE792D095A9 (telefone_id), PRIMARY KEY(cliente_id, telefone_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE cliente_ficha_anamnese (id INT AUTO_INCREMENT NOT NULL, ficha_anamnese_id INT NOT NULL, cliente_id INT NOT NULL, clinica_id INT NOT NULL, user_id BIGINT NOT NULL, data DATE NOT NULL, objetivo LONGTEXT NOT NULL, contatosEmergencia LONGTEXT NOT NULL COMMENT '(DC2Type:json)', validade DATE NOT NULL, desatualizada TINYINT(1) DEFAULT '0' NOT NULL, convenio VARCHAR(255) NOT NULL, receberSMS TINYINT(1) DEFAULT '0' NOT NULL, respostas LONGTEXT NOT NULL COMMENT '(DC2Type:json)', INDEX IDX_67CE74B67EF19F2A (ficha_anamnese_id), INDEX IDX_67CE74B6DE734E51 (cliente_id), INDEX IDX_67CE74B69CD3F6D6 (clinica_id), INDEX IDX_67CE74B6A76ED395 (user_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;

/**
 * Funcionalidades
 */
CREATE TABLE especialidade (id INT AUTO_INCREMENT NOT NULL, nome VARCHAR(255) NOT NULL, ativo TINYINT(1) NOT NULL, PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE ficha_anamnese (id INT AUTO_INCREMENT NOT NULL, clinica_id INT NOT NULL, date DATETIME NOT NULL, questoes LONGTEXT NOT NULL COMMENT '(DC2Type:json)', ativo TINYINT(1) NOT NULL, INDEX IDX_C33A8B059CD3F6D6 (clinica_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE financeiro (id INT AUTO_INCREMENT NOT NULL, nome_item VARCHAR(255) NOT NULL, data DATE NOT NULL, valor NUMERIC(10, 2) NOT NULL, tipo_conta VARCHAR(255) NOT NULL COMMENT 'pagar / receber', pendente TINYINT(1) DEFAULT '0' NOT NULL, categoria VARCHAR(255) DEFAULT NULL, PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE financeirocategoria (id INT AUTO_INCREMENT NOT NULL, clinica_id INT DEFAULT NULL, nome VARCHAR(255) NOT NULL, UNIQUE INDEX UNIQ_4115418F54BD530C (nome), INDEX IDX_4115418F9CD3F6D6 (clinica_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE grupo_material (id INT AUTO_INCREMENT NOT NULL, clinica_id INT NOT NULL, nome VARCHAR(255) NOT NULL, ativo TINYINT(1) DEFAULT NULL, INDEX IDX_34534A509CD3F6D6 (clinica_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE material (id INT AUTO_INCREMENT NOT NULL, grupo_id INT NOT NULL, clinica_id INT NOT NULL, nome_material VARCHAR(100) NOT NULL, nome_fornecedor VARCHAR(100) NOT NULL, descricao VARCHAR(255) NOT NULL, quantidade_minima_estoque DOUBLE PRECISION NOT NULL, material_terceiro TINYINT(1) NOT NULL, ativo TINYINT(1) DEFAULT NULL, INDEX IDX_7CBE75959C833003 (grupo_id), INDEX IDX_7CBE75959CD3F6D6 (clinica_id), UNIQUE INDEX nomeMaterial_clinica_idx (nome_material, clinica_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE orcamento (id INT AUTO_INCREMENT NOT NULL, clinica_id INT NOT NULL, cliente_id INT NOT NULL, tabela_preco_id INT NOT NULL, data_hora DATETIME NOT NULL, data_validade DATETIME NOT NULL, tem_convenio TINYINT(1) DEFAULT '1' NOT NULL, convenios VARCHAR(255) DEFAULT NULL, acrescimo NUMERIC(10, 2) DEFAULT NULL, desconto NUMERIC(10, 2) DEFAULT NULL, subtotal NUMERIC(10, 2) NOT NULL, total NUMERIC(10, 2) NOT NULL, forma_pagamento VARCHAR(255) NOT NULL, condicao_pagamento INT NOT NULL, detalhes_condicao_pagamento LONGTEXT NOT NULL COMMENT '(DC2Type:json)', gerou_venda TINYINT(1) DEFAULT '0' NOT NULL, INDEX IDX_4B1DD46D9CD3F6D6 (clinica_id), INDEX IDX_4B1DD46DDE734E51 (cliente_id), INDEX IDX_4B1DD46DF6367BFD (tabela_preco_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE orcamento_has_servico (orcamento_id INT NOT NULL, orcamento_servico_id INT NOT NULL, INDEX IDX_BFE8C8B4A01CF1CA (orcamento_id), INDEX IDX_BFE8C8B4568366B (orcamento_servico_id), PRIMARY KEY(orcamento_id, orcamento_servico_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE orcamento_servico (id INT AUTO_INCREMENT NOT NULL, servico_id INT DEFAULT NULL, preco NUMERIC(10, 2) NOT NULL, comissaoPaga INT DEFAULT 0 NOT NULL, INDEX IDX_F109789082E14982 (servico_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE segmento (id INT AUTO_INCREMENT NOT NULL, nome VARCHAR(255) NOT NULL, ativo TINYINT(1) NOT NULL, PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE servico_categoria (id INT AUTO_INCREMENT NOT NULL, clinica_id INT DEFAULT NULL, nome VARCHAR(255) NOT NULL, INDEX IDX_F42E70E39CD3F6D6 (clinica_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE servico_material (id INT AUTO_INCREMENT NOT NULL, servico_id INT DEFAULT NULL, material_id INT DEFAULT NULL, quantidade_material_utilizado DOUBLE PRECISION NOT NULL, INDEX IDX_92EABE6182E14982 (servico_id), INDEX IDX_92EABE61E308AC6F (material_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
CREATE TABLE servico (id INT AUTO_INCREMENT NOT NULL, categoria_id INT DEFAULT NULL, clinica_id INT DEFAULT NULL, titulo VARCHAR(255) NOT NULL, descricao VARCHAR(255) NOT NULL, tempo_medio_duracao INT NOT NULL, agendamento_externo TINYINT(1) NOT NULL, INDEX IDX_14873CC3397707A (categoria_id), INDEX IDX_14873CC9CD3F6D6 (clinica_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
