CREATE TABLE venda_has_pagamento (id INT AUTO_INCREMENT NOT NULL, venda_id INT NOT NULL, clinica_id INT NOT NULL, forma_pagamento VARCHAR(255) NOT NULL, data_hora DATETIME NOT NULL, valor_pago NUMERIC(10, 2) NOT NULL, INDEX IDX_790EDADE924517DF (venda_id), INDEX IDX_790EDADE9CD3F6D6 (clinica_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
