CREATE TABLE venda_has_agenda (venda_id INT NOT NULL, agenda_id INT NOT NULL, INDEX IDX_230DBEBE924517DF (venda_id), UNIQUE INDEX UNIQ_230DBEBEEA67784A (agenda_id), PRIMARY KEY(venda_id, agenda_id)) DEFAULT CHARACTER SET utf8 COLLATE utf8_unicode_ci ENGINE = InnoDB;
