{
	"info": {
		"_postman_id": "b0116d0c-5262-4a39-b4a1-62d60e55fe48",
		"name": "User Role",
		"schema": "https://schema.getpostman.com/json/collection/v2.1.0/collection.json"
	},
	"item": [
		{
			"name": "Get User Roles",
			"event": [
				{
					"listen": "test",
					"script": {
						"id": "ba3e0785-3bad-4bc9-aba6-dd1f0cf3c2e4",
						"exec": [
							"const schema = {",
							"    \"type\": \"object\",",
							"    \"required\": [",
							"        \"access_token\",",
							"        \"expires_in\",",
							"        \"token_type\",",
							"        \"scope\",",
							"        \"refresh_token\"",
							"    ],",
							"    \"properties\": {",
							"        \"access_token\": {",
							"            \"type\": \"string\"",
							"        },",
							"        \"expires_in\": {",
							"            \"type\": \"integer\"",
							"        },",
							"        \"token_type\": {",
							"            \"type\": \"string\"",
							"        },",
							"        \"scope\": {",
							"            \"type\": \"string\"",
							"        },",
							"        \"refresh_token\": {",
							"            \"type\": \"string\"",
							"        }",
							"    }",
							"};",
							"",
							"let body = JSON.parse(responseBody);",
							"",
							"tests[\"Status code is 200\"] = responseCode.code === 200;",
							"tests[\"Schema validation\"] = tv4.validate(body, schema);",
							"",
							"postman.setEnvironmentVariable(\"access_token\", body.access_token);",
							"postman.setEnvironmentVariable(\"refresh_token\", body.refresh_token);"
						],
						"type": "text/javascript"
					}
				}
			],
			"request": {
				"auth": {
					"type": "noauth"
				},
				"method": "GET",
				"header": [
					{
						"key": "Authorization",
						"value": "Bearer {{access_token}}",
						"type": "text"
					}
				],
				"body": {
					"mode": "raw",
					"raw": ""
				},
				"url": {
					"raw": "{{local}}/user-roles",
					"host": [
						"{{local}}"
					],
					"path": [
						"user-roles"
					]
				},
				"description": "Retorna uma refresh token, que poderá ser utilizada a cada uma hora para obter uma nova access token, e sem que o usuário informe novamente a sua senha.\n\nhttps://apigility.org/documentation/auth/authentication-oauth2#username-and-password-access"
			},
			"response": []
		}
	]
}

